/**
 * Room Grid Component
 * 2D grid visualization of rooms with drag-drop and arrow key support
 */

import React, { useState, useEffect, useRef } from 'react';
import useWorldBuilderStore from '../store/store.js';

function RoomGrid() {
  const [cellSize, setCellSize] = useState(100);
  const [nextVnum, setNextVnum] = useState(1000);
  const [dragData, setDragData] = useState(null);
  const [roomPositions, setRoomPositions] = useState({});
  const [gridOffset, setGridOffset] = useState({ x: 0, y: 0 });
  const gridRef = useRef(null);
  
  const { currentAreaData, selectedRoom, selectRoom, createRoom, updateRoom, deleteRoom, loading } =
    useWorldBuilderStore();

  useEffect(() => {
    if (currentAreaData && currentAreaData.rooms.length > 0) {
      const maxVnum = Math.max(...currentAreaData.rooms.map(r => r.vnum));
      setNextVnum(maxVnum + 1);
      
      // Initialize room positions if not already set
      const positions = {};
      currentAreaData.rooms.forEach((room, idx) => {
        if (!roomPositions[room.vnum]) {
          positions[room.vnum] = {
            x: (idx % 5) * 120,
            y: Math.floor(idx / 5) * 120,
          };
        }
      });
      if (Object.keys(positions).length > 0) {
        setRoomPositions(prev => ({ ...prev, ...positions }));
      }
    }
  }, [currentAreaData?.rooms.length]);

  // Arrow key navigation
  useEffect(() => {
    const handleKeyDown = (e) => {
      if (!selectedRoom || !currentAreaData) return;
      
      const room = currentAreaData.rooms.find(r => r.vnum === selectedRoom);
      if (!room) return;

      let handled = false;

      // Arrow keys to navigate
      if (e.key === 'ArrowUp') {
        const northRoom = room.exits?.find(ex => ex.direction === 'north');
        if (northRoom) {
          selectRoom(northRoom.targetVnum);
          handled = true;
        }
      } else if (e.key === 'ArrowDown') {
        const southRoom = room.exits?.find(ex => ex.direction === 'south');
        if (southRoom) {
          selectRoom(southRoom.targetVnum);
          handled = true;
        }
      } else if (e.key === 'ArrowLeft') {
        const westRoom = room.exits?.find(ex => ex.direction === 'west');
        if (westRoom) {
          selectRoom(westRoom.targetVnum);
          handled = true;
        }
      } else if (e.key === 'ArrowRight') {
        const eastRoom = room.exits?.find(ex => ex.direction === 'east');
        if (eastRoom) {
          selectRoom(eastRoom.targetVnum);
          handled = true;
        }
      } else if (e.key === 'Delete') {
        // Delete selected room
        if (window.confirm(`Delete room ${selectedRoom}?`)) {
          deleteRoom(selectedRoom);
          handled = true;
        }
      } else if (e.key === 'n' && e.ctrlKey) {
        // Ctrl+N = new room
        handleCreateRoom();
        handled = true;
      }

      if (handled) {
        e.preventDefault();
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [selectedRoom, currentAreaData, selectRoom, deleteRoom]);

  const handleCreateRoom = () => {
    if (!currentAreaData) return;

    const newRoom = {
      vnum: nextVnum,
      name: `Room ${nextVnum}`,
      desc: 'A new room.',
      flags: [],
      type: 'normal',
      terrain: 'any',
      exits: [],
      npcs: [],
      objects: [],
    };

    createRoom(newRoom);
    
    // Auto-position near selected room if available
    if (selectedRoom && roomPositions[selectedRoom]) {
      setRoomPositions(prev => ({
        ...prev,
        [nextVnum]: {
          x: roomPositions[selectedRoom].x + 120,
          y: roomPositions[selectedRoom].y,
        }
      }));
    } else {
      setRoomPositions(prev => ({
        ...prev,
        [nextVnum]: {
          x: (Object.keys(prev).length % 5) * 120,
          y: Math.floor(Object.keys(prev).length / 5) * 120,
        }
      }));
    }
    
    setNextVnum(nextVnum + 1);
  };

  const handleDragStart = (e, room) => {
    setDragData({
      vnum: room.vnum,
      offsetX: e.clientX - (roomPositions[room.vnum]?.x || 0),
      offsetY: e.clientY - (roomPositions[room.vnum]?.y || 0),
    });
  };

  const handleDragOver = (e) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e) => {
    e.preventDefault();
    if (!dragData || !gridRef.current) return;

    const rect = gridRef.current.getBoundingClientRect();
    const x = e.clientX - rect.left - gridOffset.x;
    const y = e.clientY - rect.top - gridOffset.y;

    setRoomPositions(prev => ({
      ...prev,
      [dragData.vnum]: {
        x: Math.round(x / cellSize) * cellSize,
        y: Math.round(y / cellSize) * cellSize,
      }
    }));
    setDragData(null);
  };

  const handleGridClick = (e) => {
    // Click on empty space to deselect
    if (e.target === e.currentTarget) {
      selectRoom(null);
    }
  };

  if (!currentAreaData) {
    return (
      <div className="room-grid" style={{ display: 'flex', justifyContent: 'center', alignItems: 'center' }}>
        <div style={{ textAlign: 'center', color: '#999' }}>
          <p style={{ fontSize: '18px', marginBottom: '10px' }}>📂 Select an area to begin</p>
          <p style={{ fontSize: '12px' }}>Or create a new area from the left panel</p>
        </div>
      </div>
    );
  }

  const rooms = currentAreaData.rooms || [];

  return (
    <div className="room-grid">
      <div className="grid-header">
        <h2>🏗️ Room Grid ({rooms.length} rooms)</h2>
        <div className="grid-controls">
          <button onClick={handleCreateRoom} disabled={loading}>
            + New Room
          </button>
          <select value={gridSize} onChange={(e) => setGridSize(parseInt(e.target.value))}>
            <option value={5}>5x5</option>
            <option value={10}>10x10</option>
            <option value={15}>15x15</option>
            <option value={20}>20x20</option>
          </select>
        </div>
      </div>

      <div className="grid-container" onClick={handleGridClick}>
        {rooms.map((room) => (
          <div
            key={room.vnum}
            className={`grid-room ${selectedRoom === room.vnum ? 'selected' : ''}`}
            onClick={(e) => {
              e.stopPropagation();
              selectRoom(room.vnum);
            }}
            title={`${room.name} (Vnum: ${room.vnum})`}
          >
            <div className="room-vnum">{room.vnum}</div>
            <div className="room-name">{room.name}</div>
          </div>
        ))}
      </div>

      <div className="grid-info">
        <p>💡 Click rooms to select, or click empty space to create new room</p>
      </div>

      <style>{`
        .room-grid {
          display: flex;
          flex-direction: column;
          height: 100%;
          padding: 20px;
        }

        .grid-header {
          display: flex;
          justify-content: space-between;
          align-items: center;
          margin-bottom: 20px;
        }

        .grid-header h2 {
          margin: 0;
          font-size: 20px;
        }

        .grid-controls {
          display: flex;
          gap: 12px;
        }

        .grid-controls select {
          width: auto;
          padding: 8px 12px;
        }

        .grid-container {
          flex: 1;
          background: #f9f9f9;
          border: 1px solid #ddd;
          border-radius: 8px;
          padding: 20px;
          overflow: auto;
          display: grid;
          grid-template-columns: repeat(auto-fill, minmax(120px, 1fr));
          gap: 12px;
          align-content: start;
        }

        .grid-room {
          background: white;
          border: 2px solid #ddd;
          border-radius: 8px;
          padding: 12px;
          cursor: pointer;
          transition: all 0.2s;
          text-align: center;
          min-height: 100px;
          display: flex;
          flex-direction: column;
          justify-content: center;
        }

        .grid-room:hover {
          border-color: #667eea;
          box-shadow: 0 2px 8px rgba(102, 126, 234, 0.2);
        }

        .grid-room.selected {
          background: #f0f4ff;
          border-color: #667eea;
          box-shadow: 0 0 0 3px rgba(102, 126, 234, 0.1);
        }

        .room-vnum {
          font-weight: bold;
          font-size: 16px;
          color: #667eea;
          margin-bottom: 4px;
        }

        .room-name {
          font-size: 13px;
          color: #333;
          word-break: break-word;
        }

        .grid-info {
          margin-top: 12px;
          color: #999;
          font-size: 12px;
          text-align: center;
        }
      `}</style>
    </div>
  );
}

export default RoomGrid;
